import React, { useMemo, useState } from 'react';
import './UsersCatalog.css';

const mockUsers = [
  { id: 1, username: 'DarkLord', level: 5, points: 12500, joined: '2023-01-15', lastActive: '2h ago', badges: ['Top Reader', 'Collector'] },
  { id: 2, username: 'MangaMaster', level: 5, points: 9800, joined: '2023-02-20', lastActive: '5h ago', badges: ['Reviewer', 'Moderator'] },
  { id: 3, username: 'WeebQueen', level: 4, points: 7200, joined: '2023-03-10', lastActive: '1d ago', badges: ['Active Commenter'] },
  { id: 4, username: 'AnimeLover', level: 4, points: 6500, joined: '2023-03-25', lastActive: '2d ago', badges: ['Anime Fan'] },
  { id: 5, username: 'KawaiiChan', level: 3, points: 4200, joined: '2023-04-05', lastActive: '3h ago', badges: ['Rising Reader'] },
  { id: 6, username: 'OtakuKing', level: 3, points: 3800, joined: '2023-04-15', lastActive: '1h ago', badges: ['Fast Reader'] }
];

const UsersCatalog = () => {
  const [searchTerm, setSearchTerm] = useState('');
  const [sortBy, setSortBy] = useState('level');

  const users = useMemo(() => {
    const filtered = mockUsers.filter((u) => u.username.toLowerCase().includes(searchTerm.toLowerCase()));
    return filtered.sort((a, b) => {
      if (sortBy === 'points') return b.points - a.points;
      if (sortBy === 'newest') return new Date(b.joined) - new Date(a.joined);
      return b.level - a.level || b.points - a.points;
    });
  }, [searchTerm, sortBy]);

  return (
    <div className="users-catalog">
      <div className="catalog-header">
        <h2>Users</h2>
        <div className="catalog-controls">
          <div className="search-box">
            <i className="fas fa-search"></i>
            <input value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} placeholder="Search users..." />
          </div>
          <div className="sort-controls">
            <select value={sortBy} onChange={(e) => setSortBy(e.target.value)} className="sort-select">
              <option value="level">By level</option>
              <option value="points">By points</option>
              <option value="newest">Newest</option>
            </select>
          </div>
        </div>
      </div>

      <div className="users-grid">
        {users.map((user) => (
          <article key={user.id} className="user-card">
            <div className="user-top">
              <div className="user-avatar">{user.username[0]}</div>
              <div>
                <h3>{user.username}</h3>
                <p>Level {user.level} • {user.points.toLocaleString()} pts</p>
              </div>
            </div>
            <div className="user-meta">
              <span>Joined: {user.joined}</span>
              <span>Active: {user.lastActive}</span>
            </div>
            <div className="badges-list">
              {user.badges.map((badge) => <span key={badge} className="badge">{badge}</span>)}
            </div>
          </article>
        ))}
      </div>
    </div>
  );
};

export default UsersCatalog;
